	(1, 'UCq46lKycfqrBtUPTxUk_NRQ', 'Dan Music', 'Welcome to Dan Music! We\'re a YouTube channel featuring a variety of music video lyrics with accurate, on-screen lyrics for singing along.\n\nThank you for visiting our channel.\n\nMusic Submissions: https://danmusic.portal.district.biz\nContact: contact@danmusic.net', 'https://yt3.ggpht.com/cXLG7xtQpHrxiNkCFTa5vKdC058CoOh_sMtlzN2Bkz2PYlin1FavSEVsw0X_QYkfoBlAtIeH6w=s88-c-k-c0x00ffffff-no-rj', '2026-03-13 05:27:52'),
	(42, 'UCAuUUnT6oDeKwE6v1NGQxug', 'TED', 'The TED Talks channel features the best talks and performances from the TED Conference, where the world\'s leading thinkers and doers give the talk of their lives in 18 minutes (or less). Look for talks on Technology, Entertainment and Design -- plus science, business, global issues, the arts and more. You\'re welcome to link to or embed these videos, forward them to others and share these ideas with people you know.\n\nTED\'s videos may be used for non-commercial purposes under a Creative Commons License, Attribution–Non Commercial–No Derivatives (or the CC BY – NC – ND 4.0 International) and in accordance with our TED Talks Usage Policy: https://www.ted.com/about/our-organization/our-policies-terms/ted-talks-usage-policy. For more information on using TED for commercial purposes (e.g. employee learning, in a film or online course), please submit a Media Request at https://media-requests.ted.com', 'https://yt3.ggpht.com/ytc/AIdro_koIFcCOrvh0KThLNOiazAIDu6hcs8bjkGNwe1f6A_OYm8=s88-c-k-c0x00ffffff-no-rj', '2026-03-13 07:11:43');
